#include <bits/stdc++.h>
using namespace std;

int main() {
    int length;
    cin >> length;
    if (length <= 0) {
        int num, diff;
        cin >> num >> diff;
        cout << -1 << endl;
        return 0;
    }
    int arr[length];
    for (int i = 0; i < length; ++i) {
        cin >> arr[i];
    }
    int num, diff;
    cin >> num >> diff;

    int count = 0;
    for (int i = 0; i < length; ++i) {
        if (abs(arr[i] - num) <= diff) {
            count++;
        }
    }
    if (count == 0)     cout << "-1\n";
    else    cout << count << endl;
    return 0;
}

