code.C:
#include <stdio.h>
#include <stdlib.h>

int main() {
    int length;
    scanf("%d", &length);

    if (length <= 0) {
        int num, diff;
        scanf("%d %d", &num, &diff);
        printf("-1\n");
        return 0;
    }

    int arr[length];
    for (int i = 0; i < length; i++) {
        scanf("%d", &arr[i]);
    }

    int num, diff;
    scanf("%d %d", &num, &diff);

    int count = 0;
    for (int i = 0; i < length; i++) {
        if (abs(arr[i] - num) <= diff) {
            count++;
        }
    }

    if (count == 0) printf("-1\n");
    else printf("%d\n", count);

    return 0;
}

code.Java:
import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {
    public static void main (String[] args) throws java.lang.Exception
    {
        Scanner sc = new Scanner(System.in);

        int length = sc.nextInt();
        if (length <= 0) {
            int num = sc.nextInt();
            int diff = sc.nextInt();
            System.out.println(-1);
            sc.close();
            return;
        }

        int[] arr = new int[length];
        for (int i = 0; i < length; i++) {
            arr[i] = sc.nextInt();
        }

        int num = sc.nextInt();
        int diff = sc.nextInt();

        int count = 0;
        for (int i = 0; i < length; i++) {
            if (Math.abs(arr[i] - num) <= diff) {
                count++;
            }
        }

        if (count == 0) System.out.println(-1);
        else System.out.println(count);

        sc.close();
    }
}
